It could be nice to call `file`/`ldd` or something similar, on the produced outputs, so it's more clear what is being built. Otherwise the end-of run output is a bit hard to parse:
```bash
+ /opt/riscv-ilp32/bin/riscv32-unknown-elf-gcc -c start.s -o start.o
+ echo -e '#include <sys/stat.h>
          void _exit(int code) { while(1); }
          int _sbrk(int incr) { return 0; }
          int _write(int file, char *ptr, int len) { return 0; }
          int _close(int file) { return -1; }
          int _fstat(int file, struct stat *st) { st->st_mode = S_IFCHR; return 0; }
          int _isatty(int file) { return 1; }
          int _lseek(int file, int ptr, int dir) { return 0; }
          int _read(int file, char *ptr, int len) { return 0; }
          int _kill(int pid, int sig) { return -1; }
          int _getpid(void) { return -1; }'
+ /opt/riscv-ilp32/bin/riscv32-unknown-elf-gcc -g -march=rv32i -mabi=ilp32 -c syscalls.c -o syscalls.o
+ /opt/riscv-ilp32/bin/riscv32-unknown-elf-g++ -g -std=c++20 -march=rv32gc -mabi=ilp32 -nostdlib /opt/riscv-ilp32/lib/gcc/riscv32-unknown-elf/14.2.0/crtbegin.o test.o start.o syscalls.o /ci_container_base/ci/scratch/build-riscv32-unknown-elf-gcc/lib/libbitcoin_consensus.a /ci_container_base/ci/scratch/build-riscv32-unknown-elf-gcc/lib/libbitcoin_crypto.a /ci_container_base/ci/scratch/build-riscv32-unknown-elf-gcc/src/secp256k1/lib/libsecp256k1.a /opt/riscv-ilp32/riscv32-unknown-elf/lib/libstdc++.a /opt/newlib/riscv32-unknown-elf/lib/libc.a /opt/newlib/riscv32-unknown-elf/lib/libm.a /opt/riscv-ilp32/lib/gcc/riscv32-unknown-elf/14.2.0/libgcc.a -o test.elf
